	private static void corruptIndexVersion(Path indexPath) throws Exception {
		if (!Files.isRegularFile(indexPath) || Files.size(indexPath) < 8L) {
			return;
		}
		byte[] index = Files.readAllBytes(indexPath);
		index[7] = 0;
		Files.write(indexPath, index);
	}

	private static void assertDirectoryStoreLayout(Path storeDirectory) throws Exception {
		assertDirectoryPayloadLayout(storeDirectory);
		assertTrue(Files.isRegularFile(storeDirectory.resolve("metadata.bin")), "Expected metadata.bin");
	}

	private static void assertDirectoryPayloadLayout(Path storeDirectory) throws Exception {
		assertTrue(Files.isDirectory(storeDirectory), "Expected estimator persistence path to be a directory");
		assertTrue(Files.isRegularFile(storeDirectory.resolve("a/index.bin")), "Expected a/index.bin");
		assertTrue(Files.isRegularFile(storeDirectory.resolve("b/index.bin")), "Expected b/index.bin");
		assertNoLegacyPayloadFiles(storeDirectory);
	}

	private static boolean hasAnyPayloadBytes(Path storeDirectory) throws Exception {
		try (var paths = Files.walk(storeDirectory)) {
			return paths.filter(Files::isRegularFile)
					.filter(SketchBasedJoinEstimatorPersistenceTest::isSketchPartFile)
					.anyMatch(path -> {
						try {
							return Files.size(path) > 0L;
						} catch (Exception e) {
							throw new RuntimeException(e);
						}
					});
		}
	}

	private static void assertSparseIfSupported(Path path) throws Exception {
		Object blocks;
		try {
			blocks = Files.getAttribute(path, "unix:blocks");
		} catch (UnsupportedOperationException | IllegalArgumentException e) {
			return;
		}
		if (!(blocks instanceof Number)) {
			return;
		}
		long allocatedBytes = ((Number) blocks).longValue() * 512L;
		assertTrue(allocatedBytes < 64L * 1024L * 1024L,
				"Sketch part files should be sparse after tiny writes; allocatedBytes=" + allocatedBytes);
	}

