	private static boolean hasPersistedSinglePredicateSketch(SketchBasedJoinEstimator estimator, String predicate)
			throws Exception {
		int predicateHash = hash(estimator, predicate);
		for (SketchBasedJoinEstimator.DebugSketchAddress address : estimator.debugPersistedSketches()) {
			byte recType = address.recType();
			boolean isDelete = address.isDelete();
			byte axisA = address.axisA();
			int x = address.x();
			if (recType == 1 && !isDelete && axisA == (byte) SketchBasedJoinEstimator.Component.P.ordinal()
					&& x == predicateHash) {
				return true;
			}
		}
		return false;
	}

	private static Set<Byte> residentRecordTypes(SketchBasedJoinEstimator estimator) throws Exception {
		Set<Byte> recordTypes = new HashSet<>();
		for (SketchBasedJoinEstimator.DebugSketchAddress address : estimator.debugResidentSketches()) {
			recordTypes.add(address.recType());
		}
		return recordTypes;
	}

	private static int countPartFiles(Path snapshot) throws Exception {
		try (var paths = Files.walk(snapshot)) {
			return (int) paths.filter(Files::isRegularFile)
					.filter(SketchBasedJoinEstimatorPersistenceTest::isSketchPartFile)
					.count();
		}
	}

	private static int countPartFiles(Path snapshot, String baseName) throws Exception {
		try (var paths = Files.walk(snapshot)) {
			return (int) paths.filter(Files::isRegularFile)
					.filter(SketchBasedJoinEstimatorPersistenceTest::isSketchPartFile)
					.filter(path -> path.getFileName().toString().startsWith(baseName + ".part"))
					.count();
		}
	}

	private static boolean isSketchPartFile(Path path) {
		String fileName = path.getFileName().toString();
		return fileName.contains(".part") && fileName.endsWith(".sketches");
	}

	private static void assertNoLegacyPayloadFiles(Path snapshot) throws Exception {
		assertFalse(Files.exists(snapshot.resolve("a/global.sketches")), "Legacy global sketch file must not exist");
		assertFalse(Files.exists(snapshot.resolve("a/singles.sketches")), "Legacy singles sketch file must not exist");
		assertFalse(Files.exists(snapshot.resolve("a/pairs.sketches")), "Legacy pairs sketch file must not exist");
		assertFalse(Files.exists(snapshot.resolve("b/global.sketches")), "Legacy global sketch file must not exist");
		assertFalse(Files.exists(snapshot.resolve("b/singles.sketches")), "Legacy singles sketch file must not exist");
		assertFalse(Files.exists(snapshot.resolve("b/pairs.sketches")), "Legacy pairs sketch file must not exist");
	}

	@SuppressWarnings("unchecked")

	private static final class BlockingRebuildStore implements SketchStatementSource {
		private final Statement statement;
		private final CountDownLatch rebuildEntered = new CountDownLatch(1);
		private final CountDownLatch releaseRebuild = new CountDownLatch(1);

		private BlockingRebuildStore(Statement statement) {
			this.statement = statement;
		}

		boolean awaitRebuildEntry(long timeout, TimeUnit unit) throws InterruptedException {
			return rebuildEntered.await(timeout, unit);
		}

		void releaseRebuild() {
			releaseRebuild.countDown();
		}

		@Override
		public ValueFactory getValueFactory() {
			return VF;
		}

		@Override
		public CloseableIteration<? extends Statement> getStatements(
				Resource subj, IRI pred, Value obj, Resource... contexts) {
			return new CloseableIteration<Statement>() {
				private boolean emitted;

				@Override
				public void close() {
				}

				@Override
				public boolean hasNext() {
					if (emitted) {
						return false;
					}
					rebuildEntered.countDown();
					boolean interrupted = false;
					while (releaseRebuild.getCount() > 0L) {
						try {
							if (releaseRebuild.await(50, TimeUnit.MILLISECONDS)) {
								break;
							}
						} catch (InterruptedException e) {
							interrupted = true;
						}
					}
					if (interrupted) {
						Thread.currentThread().interrupt();
					}
					return !emitted;
				}

				@Override
				public Statement next() {
					emitted = true;
					return statement;
				}

				@Override
				public void remove() {
					throw new UnsupportedOperationException();
				}
			};
		}
	}

	private static final class CountingBlockingRebuildStore implements SketchStatementSource {
		private final Statement statement;
		private final CountDownLatch firstRebuildEntered = new CountDownLatch(1);
		private final CountDownLatch releaseFirstRebuild = new CountDownLatch(1);
		private final AtomicInteger rebuildEntries = new AtomicInteger();

		private CountingBlockingRebuildStore(Statement statement) {
			this.statement = statement;
		}

		boolean awaitFirstRebuildEntry(long timeout, TimeUnit unit) throws InterruptedException {
			return firstRebuildEntered.await(timeout, unit);
		}

		void releaseFirstRebuild() {
			releaseFirstRebuild.countDown();
		}

		int rebuildEntries() {
			return rebuildEntries.get();
		}

		@Override
		public ValueFactory getValueFactory() {
			return VF;
		}

		@Override
		public CloseableIteration<? extends Statement> getStatements(
				Resource subj, IRI pred, Value obj, Resource... contexts) {
			return new CloseableIteration<Statement>() {
				private boolean emitted;
				private boolean counted;

				@Override
				public void close() {
				}

				@Override
				public boolean hasNext() {
					if (emitted) {
						return false;
					}
					if (!counted) {
						counted = true;
						int entry = rebuildEntries.incrementAndGet();
						if (entry == 1) {
							firstRebuildEntered.countDown();
							boolean interrupted = false;
							while (releaseFirstRebuild.getCount() > 0L) {
								try {
									if (releaseFirstRebuild.await(50, TimeUnit.MILLISECONDS)) {
										break;
									}
								} catch (InterruptedException e) {
									interrupted = true;
								}
							}
							if (interrupted) {
								Thread.currentThread().interrupt();
							}
						}
					}
					return true;
				}

				@Override
				public Statement next() {
					emitted = true;
					return statement;
				}

				@Override
				public void remove() {
					throw new UnsupportedOperationException();
				}
			};
		}
	}
